        if (deser != null) {
            return deser;
        }

        // Otherwise: could the class be a Bean class? If not, bail out
        Class<?> rawClass = type.getRawClass();
        if (rawClass == null || isIllegalType(rawClass)) {
            throw new JsonMappingException(null, "Illegal type to deserialize: " + (rawClass != null ? rawClass.getName() : "null") + " prevented for security reasons");
        }
        // For checks like [databind#1599]
