    private boolean isIllegalType(Class<?> rawClass) {
        // Check against a configurable blacklist of illegal types
        List<String> illegalTypeNames = getIllegalTypeNames();
        return illegalTypeNames.contains(rawClass.getName());
    }

    private List<String> getIllegalTypeNames() {
        // This method should provide the list of illegal type names, possibly from configuration
        // For demonstration, a hardcoded list is used here
        return Arrays.asList("com.sun.org.apache.xalan.internal.xsltc.trax.TemplatesImpl", "org.example.MaliciousClass");
    }
